fixed_code:
trait SecretCompare {
    fn compare(&self, other: &[u8]) -> bool;
}

impl SecretCompare for [u8] {
    fn compare(&self, other: &[u8]) -> bool {
        self.len() == other.len() && self.iter().zip(other).all(|(a, b)| a == b)
    }
}

fn main() {
    let secret = vec![1, 2, 3];
    let guess = vec![4, 5];
    println!("Is equal: {}
", secret.compare(&guess));
}

